CREATE TABLE attendee_profiles (user_id uuid PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE, company text, job_title text, industry text, company_size text, linkedin_url text, interests jsonb NOT NULL DEFAULT '[]'::jsonb, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE attendee_profile_consents (user_id uuid PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE, share_profile_with_exhibitors boolean NOT NULL DEFAULT false, updated_at timestamptz NOT NULL DEFAULT now());
GRANT SELECT, INSERT, UPDATE ON attendee_profiles, attendee_profile_consents TO app_tenant; GRANT ALL PRIVILEGES ON attendee_profiles, attendee_profile_consents TO app_platform;
ALTER TABLE attendee_profiles ENABLE ROW LEVEL SECURITY; ALTER TABLE attendee_profiles FORCE ROW LEVEL SECURITY; ALTER TABLE attendee_profile_consents ENABLE ROW LEVEL SECURITY; ALTER TABLE attendee_profile_consents FORCE ROW LEVEL SECURITY;
CREATE OR REPLACE FUNCTION concourse.exhibitor_can_read_attendee_profile(target_user_id uuid) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $$ SELECT EXISTS (SELECT 1 FROM attendee_profile_consents consent JOIN lead_submissions submission ON submission.attendee_user_id = consent.user_id JOIN event_exhibitors exhibitor ON exhibitor.id = submission.event_exhibitor_id WHERE consent.user_id = target_user_id AND consent.share_profile_with_exhibitors AND exhibitor.organization_id = NULLIF(current_setting('app.current_org_id', true), '')::uuid); $$;
CREATE POLICY self_or_authorized_exhibitor_read ON attendee_profiles FOR SELECT USING (user_id = current_setting('app.current_user_id', true)::uuid OR concourse.exhibitor_can_read_attendee_profile(user_id));
CREATE POLICY self_write ON attendee_profiles FOR INSERT WITH CHECK (user_id = current_setting('app.current_user_id', true)::uuid); CREATE POLICY self_update ON attendee_profiles FOR UPDATE USING (user_id = current_setting('app.current_user_id', true)::uuid) WITH CHECK (user_id = current_setting('app.current_user_id', true)::uuid);
CREATE POLICY self_read ON attendee_profile_consents FOR SELECT USING (user_id = current_setting('app.current_user_id', true)::uuid); CREATE POLICY self_write ON attendee_profile_consents FOR INSERT WITH CHECK (user_id = current_setting('app.current_user_id', true)::uuid); CREATE POLICY self_update ON attendee_profile_consents FOR UPDATE USING (user_id = current_setting('app.current_user_id', true)::uuid) WITH CHECK (user_id = current_setting('app.current_user_id', true)::uuid);
ALTER TABLE lead_submissions ADD COLUMN idempotency_key text NOT NULL DEFAULT concourse.uuid_generate_v7()::text; CREATE UNIQUE INDEX lead_submissions_exhibitor_idempotency_key ON lead_submissions(event_exhibitor_id, idempotency_key);
CREATE FUNCTION concourse.assert_lead_submission_integrity() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN IF NOT EXISTS (SELECT 1 FROM event_exhibitors exhibitor JOIN lead_forms form ON form.event_exhibitor_id = exhibitor.id WHERE exhibitor.id = NEW.event_exhibitor_id AND exhibitor.event_id = NEW.event_id AND form.id = NEW.lead_form_id) THEN RAISE EXCEPTION 'lead submission event, exhibitor, and form must match'; END IF; RETURN NEW; END; $$;
CREATE TRIGGER lead_submissions_integrity BEFORE INSERT OR UPDATE ON lead_submissions FOR EACH ROW EXECUTE FUNCTION concourse.assert_lead_submission_integrity();
CREATE FUNCTION concourse.assert_lead_submission_value_integrity() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN IF NOT EXISTS (SELECT 1 FROM lead_submissions submission JOIN lead_form_fields field ON field.lead_form_id = submission.lead_form_id WHERE submission.id = NEW.lead_submission_id AND field.id = NEW.lead_form_field_id) THEN RAISE EXCEPTION 'lead submission value field must belong to submission form'; END IF; RETURN NEW; END; $$;
CREATE TRIGGER lead_submission_values_integrity BEFORE INSERT ON lead_submission_values FOR EACH ROW EXECUTE FUNCTION concourse.assert_lead_submission_value_integrity();
CREATE FUNCTION concourse.prevent_lead_submission_mutation() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN RAISE EXCEPTION 'lead submissions are immutable'; END; $$;
CREATE TRIGGER lead_submissions_immutable BEFORE UPDATE ON lead_submissions FOR EACH ROW EXECUTE FUNCTION concourse.prevent_lead_submission_mutation(); CREATE TRIGGER lead_submission_values_immutable BEFORE UPDATE ON lead_submission_values FOR EACH ROW EXECUTE FUNCTION concourse.prevent_lead_submission_mutation();
